class Solution {
public:
    string resultingString(string s) {
        while (true) {
            bool found = false;
            for (int i = 0; i < s.size() - 1; i++) {
                if (abs(s[i] - s[i + 1]) == 1 || abs(s[i] - s[i + 1]) == 25) {
                    s.erase(i, 2);
                    found = true;
                    break;
                }
            }
            if (!found) break;
        }
        return s;
    }
};
